mapper.select:
select * from sys_user

     and username like concat('%', #{username}, '%')
     and role = #{role}
     and subject = #{subject}

order by id desc

mapper.update:
update sys_user set username=#{username}, name=#{name}, role=#{role}, subject=#{subject}, avatar=#{avatar}, grade=#{grade}
, password=#{password}
where id=#{id}
